  sha256sum = sha256()
  with open(path, 'rb') as r:
    while True:
      chunk = r.read(32 * 1024)
      if not chunk:
        break
      sha256sum.update(chunk)

  digest = f'sha256:{sha256sum.hexdigest()}'

  try:
    await self._request('HEAD', f'/api/blobs/{digest}')
  except ResponseError as e:
