def rotate(q, v):
  q_v = jnp.concatenate([v, jnp.zeros_like(v[Ellipsis, :1])], axis=-1)
  return im(multiply(multiply(q, q_v), conjugate(q)))

def plus_eps(x):
  return jnp.where(
      jnp.abs(x) < tiny_val, tiny_val, jnp.nextafter(jnp.float32(x), jnp.inf)
  )

def minus_eps(x):
  return jnp.where(
      jnp.abs(x) < tiny_val, -tiny_val, jnp.nextafter(jnp.float32(x), -jnp.inf)
  )

def safe_exp(x):
  return generate_safe_fn(
      jnp.exp,
      lambda _, y, x_dot: y * x_dot,
      (min_val, np.nextafter(np.log(max_val), np.float32(0))),
  )(x)

def safe_log(x):
  return generate_safe_fn(
      jnp.log,
      lambda x, _, x_dot: x_dot / x,
      (tiny_val, max_val),
  )(x)

def safe_sqrt(x):
  return generate_safe_fn(
      jnp.sqrt,
      lambda x, _, x_dot: 0.5 * x_dot / jnp.sqrt(jnp.maximum(tiny_val, x)),
      (0, max_val),
  )(x)

def power_ladder_max_output(p):
  return select(
      [
          (p == -jnp.inf, 1),
          (p >= 0, jnp.inf),
      ],
      safe_div(p - 1, p),
  )

def safe_log1p(x):
  return generate_safe_fn(
      jnp.log1p,
      lambda x, _, x_dot: x_dot / (1 + x),
      (np.nextafter(np.float32(-1), np.float32(0)), max_val),
  )(x)

def power_ladder(x, p, premult=None, postmult=None):
  if premult is not None:
    x = x * premult
  xp = jnp.abs(x)
  xs = xp / jnp.maximum(tiny_val, jnp.abs(p - 1))
  p_safe = clip_finite_nograd(remove_zero(p))
  y = safe_sign(x) * select(
      [
          (p == 1, xp),
          (p == 0, safe_log1p(xp)),
          (p == -jnp.inf, -safe_expm1(-xp)),
          (p == jnp.inf, safe_expm1(xp)),
      ],
      clip_finite_nograd(
          jnp.abs(p_safe - 1) / p_safe * ((xs + 1) ** p_safe - 1)
      ),
  )
  if postmult is not None:
    y = y * postmult
  return y

def learning_rate_decay(
    step, lr_init, lr_final, max_steps, lr_delay_steps=0, lr_delay_mult=1
):
  if lr_delay_steps > 0:
    # A kind of reverse cosine decay.
    delay_rate = lr_delay_mult + (1 - lr_delay_mult) * jnp.sin(
        0.5 * jnp.pi * jnp.clip(step / lr_delay_steps, 0, 1)
    )
  else:
    delay_rate = 1.0
  return delay_rate * log_lerp(step / max_steps, lr_init, lr_final)

def cylinder_to_gaussian(d, t0, t1, radius, diag):
  t_mean = (t0 + t1) / 2
  r_var = radius**2 / 4
  t_var = (t1 - t0) ** 2 / 12
  return lift_gaussian(d, t_mean, t_var, r_var, diag)

def compute_alpha_weights(
    density,
    tdist,
    dirs,
    **kwargs,
):
  t_delta = jnp.diff(tdist)
  delta = t_delta * jnp.linalg.norm(dirs[Ellipsis, None, :], axis=-1)
  density_delta = density * delta
  return compute_alpha_weights_helper(density_delta, **kwargs)

def apply_homogeneous_transform(transform,
                                vectors):
  vectors_h = to_homogeneous(vectors.reshape((-1, vectors.shape[-1])))
  transformed = from_homogeneous(matmul(transform, vectors_h.T).T)
  return transformed.reshape(vectors.shape)

def integrated_pos_enc(mean, var, min_deg, max_deg):
  scales = 2.0 ** jnp.arange(min_deg, max_deg)
  shape = mean.shape[:-1] + (-1,)
  scaled_mean = jnp.reshape(mean[Ellipsis, None, :] * scales[:, None], shape)
  scaled_var = jnp.reshape(var[Ellipsis, None, :] * scales[:, None] ** 2, shape)

  return expected_sin(
      jnp.concatenate([scaled_mean, scaled_mean + 0.5 * jnp.pi], axis=-1),
      jnp.concatenate([scaled_var] * 2, axis=-1),
  )

def generate_dir_enc_fn(deg_view):
  integrated_dir_enc_fn = generate_ide_fn(deg_view)

  def dir_enc_fn(xyz):
    """Function returning directional encoding (DE)."""
    return integrated_dir_enc_fn(xyz, jnp.zeros_like(xyz[Ellipsis, :1]))

  return dir_enc_fn

def parse_min_should_match(num_clauses: int, spec: str) -> int:
    def checked_parse_int(value, error_message):
        try:
            return int(value)
        except ValueError:
            raise ValueError(error_message)

    result = num_clauses
    spec = spec.strip()

    if '<' in spec:
        # we have conditional spec(s)
        space_around_less_than_pattern = re.compile(r'\s*<\s*')
        spec = space_around_less_than_pattern.sub('<', spec)
        for s in spec.split():
            parts = s.split('<', 1)
            if len(parts) < 2:
                raise ValueError("Invalid 'mm' spec: '" + s + "'. Expecting values before and after '<'")
            upper_bound = checked_parse_int(parts[0], "Invalid 'mm' spec. Expecting an integer.")
            if num_clauses <= upper_bound:
                return result
            else:
                result = parse_min_should_match(num_clauses, parts[1])
        return result

    # otherwise, simple expression
    if '%' in spec:
        # percentage - assume the % was the last char. If not, let int() fail.
        spec = spec[:-1]
        percent = checked_parse_int(spec, "Invalid 'mm' spec. Expecting an integer.")
        calc = (result * percent) * (1 / 100)
        result = result + int(calc) if calc < 0 else int(calc)
    else:
        calc = checked_parse_int(spec, "Invalid 'mm' spec. Expecting an integer.")
        result = result + calc if calc < 0 else calc

    return min(num_clauses, max(result, 0))

def phrase_freq(self, tokens: List[str], slop=1) -> np.ndarray:
    if slop == 1 and len(tokens) == len(set(tokens)):
        phrase_freqs = np.zeros(len(self))
        try:
            doc_ids = self.term_mat.rows
            term_ids = [self.term_dict.get_term_id(token) for token in tokens]
            return self.posns.phrase_freqs(term_ids, doc_ids=doc_ids,
                                           phrase_freqs=phrase_freqs)
        except TermMissingError:
            return phrase_freqs
    else:
        return self.phrase_freq_every_diff(tokens, slop=slop)

def intercept(self, process: Process, message: Message):
    if isinstance(message, SendMessage):
        message.data = self._get_connection(message).c2s(message.data)
    elif isinstance(message, RecvMessage):
        message.data = self._get_connection(message).s2c(message.data)
    elif isinstance(message, CloseMessage):
        self._handle_connection_close_message(message)

def destroy(self):
    if hasattr(self, 'connections'):
        for connection in self.connections.values():
            connection.stop()
    if hasattr(self, 'server'):
        self.server.stop()
